// ============================================================
// IRIS BRAIN v3 — Dynamic deadline reader
// All deadlines live in KAI_Context.json > deadlines[]
// To add/remove/close a deadline: edit KAI_Context.json only.
// status: 'FILED' | 'COMPLETE' | 'ACTIVE' (default)
// Dates must be YYYY-MM-DD. Non-date strings are skipped.
// ============================================================

const fs = require('fs');

// --- Load context ---
let ctx = {};
try {
  ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8'));
} catch(e) {
  ctx = {};
}

const rawDeadlines = ctx.deadlines || [];
const compliance   = ctx.compliance_rules || [];
const today        = new Date();
today.setHours(0, 0, 0, 0);

// --- Helpers ---
const isValidDate = s => /^\d{4}-\d{2}-\d{2}$/.test(s) && !isNaN(new Date(s).getTime());
const daysUntil   = s => Math.ceil((new Date(s) - today) / (1000 * 60 * 60 * 24));

// --- Filter: skip FILED / COMPLETE, skip non-date strings ---
const deadlines = rawDeadlines.filter(d => {
  if (!d || !d.item || !d.date) return false;
  const st = (d.status || '').toUpperCase();
  if (st === 'FILED' || st === 'COMPLETE') return false;
  return isValidDate(d.date);
});

// --- Bucket ---
const overdue  = deadlines.filter(d => daysUntil(d.date) <  0);
const critical = deadlines.filter(d => { const n = daysUntil(d.date); return n >= 0 && n <=  7; });
const urgent   = deadlines.filter(d => { const n = daysUntil(d.date); return n >  7 && n <= 21; });
const upcoming = deadlines.filter(d => { const n = daysUntil(d.date); return n > 21 && n <= 90; });

// --- Full report (saved to file) ---
let report = `IRIS COMPLIANCE MONITOR v3\n`;
report    += `Generated: ${today.toLocaleString('en-US', { timeZone: 'America/New_York' })} EST\n`;
report    += `KAI_Context.json v${ctx.meta?.version || 'unknown'} loaded\n`;
report    += `Active deadlines tracked: ${deadlines.length} | Filed/Complete skipped: ${rawDeadlines.length - deadlines.length}\n\n`;

if (overdue.length) {
  report += '🔴 OVERDUE:\n';
  overdue.forEach(d => {
    report += `  • ${d.item} — ${Math.abs(daysUntil(d.date))}d overdue [${d.entity || '?'}]\n`;
    if (d.notes) report += `    Notes: ${d.notes}\n`;
  });
  report += '\n';
}

if (critical.length) {
  report += '🚨 CRITICAL (≤7 days):\n';
  critical.forEach(d => {
    report += `  • ${d.item} — ${daysUntil(d.date)}d (${d.date}) [${d.entity || '?'}] Owner: ${d.owner || 'Kevin'}\n`;
    if (d.notes) report += `    Notes: ${d.notes}\n`;
  });
  report += '\n';
}

if (urgent.length) {
  report += '⚠️  URGENT (8-21 days):\n';
  urgent.forEach(d => {
    report += `  • ${d.item} — ${daysUntil(d.date)}d (${d.date}) [${d.entity || '?'}]\n`;
    if (d.notes) report += `    Notes: ${d.notes}\n`;
  });
  report += '\n';
}

if (upcoming.length) {
  report += '📅 UPCOMING (22-90 days):\n';
  upcoming.forEach(d => {
    report += `  • ${d.item} — ${daysUntil(d.date)}d (${d.date}) [${d.entity || '?'}]\n`;
  });
  report += '\n';
}

if (!overdue.length && !critical.length && !urgent.length) {
  report += '✅ No overdue, critical, or urgent items.\n\n';
}

report += `COMPLIANCE RULES:\n${compliance.map(r => '• ' + r).join('\n')}\n\n`;
report += `REGULATORY WATCH:\n`;
report += `• FAA Part 108 BVLOS final rule INCOMING — flagged for Atlas SBIR\n`;
report += `• FAA-2022-1258 BVLOS rulemaking active\n`;
report += `• OMB M-26-02 federal drone compliance deadline: 2026-05-20\n`;
report += `• DJI ban risk — NDAA Section 1828 security review status: monitor\n`;

// --- Save report ---
const outputPath = `/data/Aidan_Outputs/Iris/Iris_Report_${today.toISOString().replace(/[:.]/g, '-')}.txt`;
fs.mkdirSync('/data/Aidan_Outputs/Iris', { recursive: true });
fs.writeFileSync(outputPath, report, 'utf8');

// --- WhatsApp summary (concise) ---
let whatsappMsg = `🛡️ IRIS COMPLIANCE v3\n`;
whatsappMsg    += `${today.toLocaleDateString('en-US', { timeZone: 'America/New_York', month:'short', day:'numeric' })} | Tracking: ${deadlines.length} items\n\n`;

if (overdue.length) {
  whatsappMsg += `🔴 OVERDUE (${overdue.length}):\n`;
  overdue.forEach(d => { whatsappMsg += `• ${d.item} — ${Math.abs(daysUntil(d.date))}d ago\n`; });
  whatsappMsg += '\n';
}
if (critical.length) {
  whatsappMsg += `🚨 CRITICAL (${critical.length}):\n`;
  critical.forEach(d => { whatsappMsg += `• ${d.item} — ${daysUntil(d.date)}d\n`; });
  whatsappMsg += '\n';
}
if (urgent.length) {
  whatsappMsg += `⚠️ URGENT (${urgent.length}):\n`;
  urgent.forEach(d => { whatsappMsg += `• ${d.item} — ${daysUntil(d.date)}d\n`; });
  whatsappMsg += '\n';
}
if (!overdue.length && !critical.length && !urgent.length) {
  whatsappMsg += `✅ All clear — no critical or overdue items.\n\n`;
}
whatsappMsg += `Part 108 BVLOS: INCOMING — Atlas flagged.`;

const summary = `IRIS v3 COMPLETE | Critical: ${critical.length} | Urgent: ${urgent.length} | Overdue: ${overdue.length} | Saved: ${outputPath}`;

return [{
  json: {
    report,
    whatsappMsg,
    summary,
    criticalCount: critical.length,
    urgentCount:   urgent.length,
    overdueCount:  overdue.length,
    activeCount:   deadlines.length,
    skippedCount:  rawDeadlines.length - deadlines.length,
    savedTo:       outputPath
  }
}];

const http = require('http');
const { whatsappMsg, summary = 'Iris complete.', criticalCount, urgentCount, overdueCount } = $input.first().json;

// --- Send WhatsApp ---
const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: whatsappMsg } });
const opts = {
  hostname: 'host.docker.internal', port: 8081,
  path: '/message/sendText/Aidan', method: 'POST',
  headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) }
};
await new Promise(r => {
  const req = http.request(opts, res => { res.on('data', () => {}); res.on('end', r); });
  req.on('error', r);
  req.write(msgBody);
  req.end();
});

// --- Callback to Aidan orchestrator ---
const cbBody = JSON.stringify({ agent: 'Iris', summary, criticalCount, urgentCount, overdueCount, timestamp: new Date().toISOString() });
const cbOpts = {
  hostname: 'host.docker.internal', port: 5678,
  path: '/webhook/aidan-callback', method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
};
const cbReq = http.request(cbOpts, res => { res.on('data', () => {}); res.on('end', () => {}); });
cbReq.on('error', () => {});
cbReq.write(cbBody);
cbReq.end();

return [{ json: { success: true, agent: 'Iris', summary } }];
